const CELL_PARTS = {
  plant: ["wall","membrane","cytoplasm","nucleus","vacuole","chloroplast","mitochondria"],
  animal: ["membrane","cytoplasm","nucleus","vacuole","mitochondria"]
};

let currentCell = "plant";
let currentPart = null;

const legendBox = document.getElementById('legendBox');
const detailBox = document.getElementById('detailBox');
const stageHint = document.getElementById('stageHint');

function badgeClass(found){
  if(found === "plant") return "plant";
  if(found === "animal") return "animal";
  return "both";
}
function badgeLabel(found){
  if(found === "plant") return "พบในเซลล์พืชเท่านั้น";
  if(found === "animal") return "พบในเซลล์สัตว์เท่านั้น";
  return "พบในเซลล์พืชและเซลล์สัตว์";
}

function renderLegend(){
  legendBox.innerHTML = "";
  CELL_PARTS[currentCell].forEach(key=>{
    const o = ORGANELLES[key];
    const chip = document.createElement('div');
    chip.className = "legend-chip" + (currentPart===key ? " active":"");
    chip.dataset.part = key;
    chip.innerHTML = `<span class="sw"></span>${o.name}`;
    chip.onclick = ()=> selectPart(key);
    legendBox.appendChild(chip);
  });
}

function selectPart(key){
  currentPart = key;
  const o = ORGANELLES[key];
  const shotSrc = (ORGAN_IMAGES[currentCell] && ORGAN_IMAGES[currentCell][key]) ? ORGAN_IMAGES[currentCell][key] : null;
  const shotHtml = shotSrc ? `<img class="organelle-shot" src="${shotSrc}" alt="ภาพตัดขยาย ${o.name}">` : '';
  detailBox.innerHTML = `
    ${shotHtml}
    <span class="badge ${badgeClass(o.found)}">${badgeLabel(o.found)}</span>
    <h3>${o.name}</h3>
    <div class="en">${o.en}</div>
    <p class="desc">${o.desc}</p>
  `;
  // highlight svg
  document.querySelectorAll('.cellsvg .part-shape').forEach(el=>{
    if(el.dataset.part === key){ el.classList.add('glow'); el.classList.remove('dim'); }
    else { el.classList.add('dim'); el.classList.remove('glow'); }
  });
  document.querySelectorAll('.cellsvg .hotspot').forEach(el=>{
    el.classList.toggle('active', el.dataset.part === key);
  });
  renderLegend();
}

function resetHighlight(){
  document.querySelectorAll('.cellsvg .part-shape').forEach(el=>{
    el.classList.remove('dim'); el.classList.remove('glow');
  });
  document.querySelectorAll('.cellsvg .hotspot').forEach(el=> el.classList.remove('active'));
}

document.querySelectorAll('.hotspot').forEach(h=>{
  h.addEventListener('click', ()=> selectPart(h.dataset.part));
});

document.querySelectorAll('.lab-tab').forEach(tab=>{
  tab.addEventListener('click', ()=>{
    document.querySelectorAll('.lab-tab').forEach(t=>t.classList.remove('active'));
    tab.classList.add('active');
    currentCell = tab.dataset.cell;
    currentPart = null;
    resetHighlight();
    document.getElementById('plantStage').style.display = currentCell==='plant' ? 'block':'none';
    document.getElementById('animalStage').style.display = currentCell==='animal' ? 'block':'none';
    const stage = document.getElementById('labStage');
    stage.classList.toggle('stage-plant', currentCell==='plant');
    stage.classList.toggle('stage-animal', currentCell==='animal');
    stageHint.innerHTML = currentCell==='plant'
      ? '<b>เซลล์พืช</b> — แตะตัวเลขบนภาพ หรือเลือกจากรายการด้านขวา'
      : '<b>เซลล์สัตว์</b> — แตะตัวเลขบนภาพ หรือเลือกจากรายการด้านขวา';
    detailBox.innerHTML = '<p class="placeholder">👆 แตะที่ส่วนประกอบของเซลล์ในภาพ หรือเลือกชื่อจากรายการด้านบน เพื่อดูหน้าที่ของแต่ละโครงสร้าง</p>';
    renderLegend();
  });
});

document.querySelectorAll('.video-thumb').forEach(thumb=>{
  thumb.addEventListener('click', ()=>{
    const id = thumb.closest('.video-card').dataset.yt;
    thumb.innerHTML = `<iframe src="https://www.youtube.com/embed/${id}?autoplay=1" title="YouTube video" allow="autoplay; encrypted-media" allowfullscreen></iframe>`;
  });
});

renderLegend();

// accordion
document.querySelectorAll('.acc-head').forEach(head=>{
  head.addEventListener('click', ()=>{
    const item = head.parentElement;
    const body = item.querySelector('.acc-body');
    const isOpen = item.classList.contains('open');
    document.querySelectorAll('.acc-item').forEach(i=>{
      i.classList.remove('open');
      i.querySelector('.acc-body').style.maxHeight = null;
    });
    if(!isOpen){
      item.classList.add('open');
      body.style.maxHeight = body.scrollHeight + "px";
    }
  });
});
// open first accordion by default
window.addEventListener('load', ()=>{
  const first = document.querySelector('.acc-item.open .acc-body');
  if(first) first.style.maxHeight = first.scrollHeight + "px";
});

// nav active state on scroll
const navLinks = document.querySelectorAll('#navLinks a');
const sections = [...navLinks].map(l=> document.querySelector(l.getAttribute('href')));
function onScroll(){
  let idx = 0;
  sections.forEach((s,i)=>{
    if(s && window.scrollY + 120 >= s.offsetTop) idx = i;
  });
  navLinks.forEach((l,i)=> l.classList.toggle('active', i===idx));
}
window.addEventListener('scroll', onScroll);
onScroll();

