const questionList = document.getElementById('questionList');
QUIZ.forEach((item, qi)=>{
  const block = document.createElement('div');
  block.className = 'q-block';
  let optsHtml = item.opts.map((opt,oi)=>`
    <label class="q-opt" data-qi="${qi}" data-oi="${oi}">
      <input type="radio" name="q${qi}" value="${oi}" required>
      <span>${opt}</span>
    </label>`).join('');
  block.innerHTML = `<div class="q-text">${item.q}</div>${optsHtml}`;
  questionList.appendChild(block);
});

document.getElementById('quizForm').addEventListener('submit', function(e){
  e.preventDefault();
  let score = 0;
  QUIZ.forEach((item, qi)=>{
    const picked = document.querySelector(`input[name="q${qi}"]:checked`);
    const pickedVal = picked ? parseInt(picked.value) : -1;
    if(pickedVal === item.correct) score++;
    document.querySelectorAll(`.q-opt[data-qi="${qi}"]`).forEach(label=>{
      const oi = parseInt(label.dataset.oi);
      if(oi === item.correct) label.classList.add('correct');
      else if(oi === pickedVal) label.classList.add('wrong');
    });
  });
  this.classList.add('locked');
  document.getElementById('quizSubmitBtn').style.display = 'none';
  const banner = document.getElementById('resultBanner');
  banner.classList.add('show');
  document.getElementById('scoreText').innerHTML = score + '<small> / 10</small>';
  const msg = score >= 8 ? 'ยอดเยี่ยมมาก! เข้าใจโครงสร้างเซลล์ดีมากครับ/ค่ะ 🎉'
            : score >= 5 ? 'ทำได้ดี ลองทวนข้อที่ตอบผิด (ไฮไลต์สีแดง) อีกครั้งนะครับ/ค่ะ'
            : 'ลองกลับไปอ่านมุมความรู้และดูคำตอบที่ถูก (ไฮไลต์สีเขียว) อีกรอบนะครับ/ค่ะ';
  document.getElementById('scoreMsg').textContent = msg;
  banner.scrollIntoView({behavior:'smooth', block:'center'});

  /* ── ส่งคะแนนไป Google Sheet ─────────────────────────────── */
  (function sendToSheet() {
    const GAS_URL = 'https://script.google.com/macros/s/AKfycbzFZzw3zu1ndDjF-4Z2j3OAQc-Q-bOm83QW5TN3Rk1fervuv_qmy7jlw7v0g9Iknbl6/exec';

    // อ่านข้อมูลนักเรียนจากฟอร์ม
    const form    = document.getElementById('quizForm');
    const prefix  = (form.querySelector('input[name="prefix"]:checked') || {}).value || '';
    const fullname = (form.querySelector('input[name="fullname"]') || {}).value || '';
    const room    = (form.querySelector('input[name="room"]')     || {}).value || '';
    const number  = (form.querySelector('input[name="number"]')   || {}).value || '';

    // สถานะ: กำลังส่ง
    const statusEl = document.createElement('p');
    statusEl.id    = 'sheetStatus';
    statusEl.style.cssText = 'font-size:13px;margin-top:10px;color:rgba(255,255,255,.75);';
    statusEl.textContent   = '⏳ กำลังบันทึกคะแนน…';
    banner.appendChild(statusEl);

    // สร้าง URL params
    const params = new URLSearchParams({
      prefix:   prefix,
      fullname: fullname,
      room:     room,
      number:   number,
      score:    score,
      total:    10,
      subject:  'โครงสร้างและหน้าที่ของเซลล์',
      timestamp: new Date().toLocaleString('th-TH', { timeZone: 'Asia/Bangkok' })
    });

    // ส่งด้วย fetch (no-cors เพื่อหลีกเลี่ยง CORS error)
    fetch(GAS_URL + '?' + params.toString(), { method: 'GET', mode: 'no-cors' })
      .then(function () {
        statusEl.textContent = '✅ บันทึกคะแนนเรียบร้อยแล้ว!';
        statusEl.style.color = '#a8f0c6';
      })
      .catch(function (err) {
        console.warn('Google Sheet error:', err);
        statusEl.textContent = '⚠️ บันทึกไม่สำเร็จ — กรุณาแจ้งครู';
        statusEl.style.color = '#ffcba0';
      });
  })();
});

/* ---------------- LIGHTBOX for step photos ---------------- */
function openLightbox(src){
  document.getElementById('lightboxImg').src = src;
  document.getElementById('lightbox').classList.add('show');
}
function closeLightbox(){
  document.getElementById('lightbox').classList.remove('show');
}
/* ── STEP PHOTO UPLOAD (คลิกรูปเพื่ออัปโหลดรูปจริง) ─────────────── */
(function () {
  function initUploads() {
    document.querySelectorAll('.step-photo-slot').forEach(function (slot) {
      var img = slot.querySelector('img');
      if (!img) return;

      // สร้าง input file ซ่อน
      var inp = document.createElement('input');
      inp.type = 'file';
      inp.accept = 'image/*';
      inp.style.display = 'none';
      slot.appendChild(inp);

      // overlay badge "คลิกเพื่อเพิ่มรูป"
      var badge = document.createElement('span');
      badge.className = 'upload-badge';
      badge.textContent = '📷 คลิก';
      slot.appendChild(badge);

      img.title = 'คลิกเพื่อเลือกรูปภาพจากเครื่อง';
      img.style.cursor = 'pointer';

      img.addEventListener('click', function () { inp.click(); });

      inp.addEventListener('change', function (e) {
        if (!e.target.files[0]) return;
        var reader = new FileReader();
        reader.onload = function (ev) {
          img.src = ev.target.result;
          badge.style.display = 'none';
          img.style.outline = '2px solid var(--leaf, #5C8A4A)';
        };
        reader.readAsDataURL(e.target.files[0]);
      });
    });
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initUploads);
  } else {
    initUploads();
  }
})();
